window.customJsFunctions={importContentFromWord:function(){window.sfBlazor.instances.rteCustomWordUpload.element.click()},exportContentToPDF:function(n){const t=`<html><head></head><body>${n}</body></html>`;fetch("https://blazor.syncfusion.com/services/production/api/RichTextEditor/ExportToPdf",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({html:t})}).then(n=>{if(!n.ok)throw new Error(`HTTP error! Status: ${n.status}`);return n.blob()}).then(n=>{const i=window.URL.createObjectURL(n),t=document.createElement("a");t.href=i;t.download="Sample.pdf";document.body.appendChild(t);t.click();document.body.removeChild(t);window.URL.revokeObjectURL(i)}).catch(n=>{console.error("Fetch error:",n)})},exportContentToWord:function(n){const t=`<html><head></head><body>${n}</body></html>`;fetch("https://blazor.syncfusion.com/services/production/api/RichTextEditor/ExportToDocx",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({html:t})}).then(n=>{if(!n.ok)throw new Error(`HTTP error! Status: ${n.status}`);const t="Result.docx";return n.blob().then(n=>({blob:n,filename:t}))}).then(({blob:n,filename:t})=>{const r=window.URL.createObjectURL(n),i=document.createElement("a");i.href=r;i.download=t;document.body.appendChild(i);i.click();document.body.removeChild(i);window.URL.revokeObjectURL(r)}).catch(n=>{console.error("Fetch error:",n)})}}